module top_module(
    input clk,
    input rst,
    output reg [2:0] out
);reg [2:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        count <= 3'b0;
    end else if (count == 3'b111) begin
        count <= 3'b0;
    end else begin
        count <= count + 1;
    end
end

assign out = count;

endmodule
